SELECT COUNT(stream_id) AS active_streams_count
FROM code_streams
WHERE is_active = 1;

SELECT COUNT(*) AS successful_steps
FROM execution_steps
WHERE user_id = 0 AND environment = 'development' AND status = 'success';

SELECT stream_name, description
FROM code_streams
WHERE is_active = 1;

SELECT MAX(version_number) AS latest_version
FROM version_history
WHERE row_id = 1;

SELECT user_id, MAX(timestamp) AS most_recent_action_time
FROM execution_steps
GROUP BY user_id;

SELECT step_id
FROM execution_steps
ORDER BY timestamp;
